Add POST /api/directory endpoint:
```typescript
router.post('/api/directory', async (req, res) => {
  const { parentPath, folderName } = req.body;

  // Validate folderName is kebab-case using AGENT_NAME_REGEX
  const nameValidation = validateAgentName(folderName);
  if (!nameValidation.valid) {
    return res.status(400).json({ error: nameValidation.error });
  }

  // Boundary-validate parentPath using PathValidator
  // (use existing boundary validation pattern from the codebase)

  const fullPath = path.join(parentPath, folderName);

  // Check if already exists
  try {
    await fs.stat(fullPath);
    return res.status(409).json({ error: 'Directory already exists' });
  } catch {
    // Expected — directory doesn't exist
  }

  // Create directory
  try {
    await fs.mkdir(fullPath, { recursive: false });
    return res.status(201).json({ path: fullPath });
  } catch (err) {
    return res.status(500).json({ error: 'Failed to create directory' });
  }
});
```

Validation rules:
- parentPath required, must pass boundary validation
- folderName required, kebab-case only (AGENT_NAME_REGEX)
- Return 409 if directory exists
- Return 400 if name invalid
- Return 403 if outside boundary
- Return 201 + { path } on success

