Build the full agent creation pipeline: mkdir + scaffold + optional template + register. Add the new transport.createAgent(opts) method.

**File: apps/server/src/routes/agents.ts**

Add POST /api/agents endpoint (the full creation pipeline):

```typescript
router.post('/', async (req, res) => {
  // 1. Parse & validate CreateAgentOptionsSchema
  const parsed = CreateAgentOptionsSchema.safeParse(req.body);
  if (!parsed.success) return res.status(400).json({ error: parsed.error.format() });
  const opts = parsed.data;

  // 2. Resolve directory
  const defaultBase = config.agents?.defaultDirectory || path.join(dorkHome, 'agents');
  const resolvedPath = opts.directory || path.join(defaultBase, opts.name);

  // 3. Boundary-validate resolved path (PathValidator)
  // Use existing PathValidator pattern

  // 4. Check collision
  try {
    await fs.stat(resolvedPath);
    return res.status(409).json({ error: 'Directory already exists', path: resolvedPath });
  } catch {
    // Expected
  }

  // 5. mkdir
  try {
    const parentDir = path.dirname(resolvedPath);
    await fs.mkdir(parentDir, { recursive: true });
    await fs.mkdir(resolvedPath, { recursive: false });
  } catch (err) {
    return res.status(500).json({ error: 'Failed to create directory' });
  }

  try {
    // 6. Template download (if provided) — delegated to template-downloader.ts (Phase 4)
    //    For Phase 1, skip template handling (will be added in Phase 4)

    // 7. Create .dork/ subdirectory
    await fs.mkdir(path.join(resolvedPath, '.dork'), { recursive: true });

    // 8. Scaffold agent.json
    const manifest = {
      id: ulid(),
      name: opts.name,
      description: opts.description || '',
      runtime: opts.runtime || 'claude-code',
      traits: opts.traits || DEFAULT_TRAITS,
      conventions: {
        soul: true,
        nope: true,
        dorkosKnowledge: true,
        ...opts.conventions,
      },
      registeredAt: new Date().toISOString(),
      registeredBy: 'dorkos-ui',
      personaEnabled: true,
      enabledToolGroups: {},
    };
    await fs.writeFile(
      path.join(resolvedPath, '.dork', 'agent.json'),
      JSON.stringify(manifest, null, 2)
    );

    // 9. Scaffold SOUL.md using renderTraits + defaultSoulTemplate
    // (Use existing trait rendering from personality convention files spec)

    // 10. Scaffold NOPE.md using defaultNopeTemplate

    // 11. If DorkBot: scaffold AGENTS.md
    if (opts.name === 'dorkbot') {
      await fs.writeFile(
        path.join(resolvedPath, 'AGENTS.md'),
        dorkbotClaudeMdTemplate()
      );
    }

    // 12. meshCore?.syncFromDisk(resolvedPath) — best-effort
    try {
      await meshCore?.syncFromDisk(resolvedPath);
    } catch {
      // best-effort
    }

    return res.status(201).json(manifest);
  } catch (err) {
    // ROLLBACK: rm -rf resolvedPath on scaffold failure
    try {
      await fs.rm(resolvedPath, { recursive: true, force: true });
    } catch {
      // best-effort cleanup
    }
    return res.status(500).json({ error: 'Failed to scaffold agent' });
  }
});
```

