Add a static lookup table for preview text. Each trait x level combination has a pre-written string. The getPreviewText function composes a personality preview from all 5 traits:

```typescript
const TRAIT_PREVIEWS: Record<string, Record<number, string>> = {
  tone: {
    1: 'Formal, precise, no-nonsense.',
    2: 'Professional with occasional warmth.',
    3: 'Friendly and approachable.',
    4: 'Conversational and upbeat.',
    5: 'Playful, witty, personality-forward.',
  },
  autonomy: {
    1: 'Always asks before acting.',
    2: 'Confirms before major actions.',
    3: 'Balances asking and acting.',
    4: 'Acts independently on most tasks.',
    5: 'Full autonomy — acts first, reports after.',
  },
  caution: {
    1: 'Extremely careful, double-checks everything.',
    2: 'Conservative approach to changes.',
    3: 'Balanced risk assessment.',
    4: 'Comfortable with calculated risks.',
    5: 'Bold and decisive, moves fast.',
  },
  detail: {
    1: 'Minimal output, just the essentials.',
    2: 'Concise with key context.',
    3: 'Balanced detail level.',
    4: 'Thorough explanations.',
    5: 'Comprehensive, detailed breakdowns.',
  },
  creativity: {
    1: 'Strictly follows established patterns.',
    2: 'Conventional with minor variations.',
    3: 'Balanced conventional and creative.',
    4: 'Explores alternative approaches.',
    5: 'Highly inventive, novel solutions.',
  },
};

export function getPreviewText(traits: TraitsMap): string {
  return Object.entries(traits)
    .map(([trait, level]) => TRAIT_PREVIEWS[trait]?.[level] ?? '')
    .filter(Boolean)
    .join(' ');
}

export function hashPreviewText(text: string): string {
  // Simple hash for AnimatePresence key stability
  let hash = 0;
  for (let i = 0; i < text.length; i++) {
    hash = ((hash << 5) - hash + text.charCodeAt(i)) | 0;
  }
  return String(hash);
}
```

