```typescript
import { spawn } from 'child_process';
import { exec as execCb } from 'child_process';
import { promisify } from 'util';
import * as fs from 'fs/promises';
import * as path from 'path';
import { downloadTemplate as gigetDownload } from 'giget';

const execAsync = promisify(execCb);

export interface TemplateDownloadResult {
  success: boolean;
  method: 'git' | 'giget';
  error?: string;
}

export interface DownloadProgressEvent {
  percent: number;
  phase: string;
}

/**
 * Download a template from a GitHub repo.
 * Tries git clone --depth 1 first, falls back to giget (tarball).
 */
export async function downloadTemplate(
  source: string,
  targetPath: string,
  onProgress?: (event: DownloadProgressEvent) => void
): Promise<TemplateDownloadResult> {
  const auth = await resolveGitAuth();

  // 1. Try git clone --depth 1
  try {
    const gitUrl = resolveGitUrl(source);
    await execGitClone(gitUrl, targetPath, auth, onProgress);
    await fs.rm(path.join(targetPath, '.git'), { recursive: true, force: true });
    return { success: true, method: 'git' };
  } catch {
    // 2. Fall back to giget
    try {
      await Promise.race([
        gigetDownload(source, { dir: targetPath, auth }),
        new Promise<never>((_, reject) =>
          setTimeout(() => reject(new Error('TIMEOUT')), 30_000)
        ),
      ]);
      return { success: true, method: 'giget' };
    } catch (err) {
      return { success: false, method: 'giget', error: classifyGigetError(err) };
    }
  }
}

/**
 * Resolve shorthand source to full git URL.
 * 'github:org/repo' → 'https://github.com/org/repo.git'
 * Full URLs pass through unchanged.
 */
export function resolveGitUrl(source: string): string {
  if (source.startsWith('github:')) {
    return `https://github.com/${source.slice(7)}.git`;
  }
  if (source.startsWith('https://') || source.startsWith('git@')) {
    return source;
  }
  // Assume github shorthand without prefix
  return `https://github.com/${source}.git`;
}

/**
 * Execute git clone with progress parsing.
 * Parses stderr lines matching 'Receiving objects: XX% (N/M)' for progress.
 */
export function execGitClone(
  url: string,
  target: string,
  auth?: string,
  onProgress?: (event: DownloadProgressEvent) => void
): Promise<void> {
  return new Promise((resolve, reject) => {
    const env = auth
      ? { ...process.env, GIT_ASKPASS: 'echo', GIT_TOKEN: auth }
      : process.env;
    const child = spawn('git', ['clone', '--depth', '1', '--progress', url, target], {
      env,
      stdio: ['ignore', 'pipe', 'pipe'],
    });

    child.stderr.on('data', (chunk: Buffer) => {
      const line = chunk.toString();
      const match = line.match(/Receiving objects:\s+(\d+)%/);
      if (match && onProgress) {
        onProgress({ percent: parseInt(match[1], 10), phase: 'receiving' });
      }
      const compressMatch = line.match(/Compressing objects:\s+(\d+)%/);
      if (compressMatch && onProgress) {
        onProgress({ percent: parseInt(compressMatch[1], 10), phase: 'compressing' });
      }
    });

    child.on('close', (code) => {
      code === 0 ? resolve() : reject(new Error(`git exit ${code}`));
    });

    child.on('error', (err) => reject(err));
  });
}

/**
 * Classify giget errors into user-friendly categories.
 */
export function classifyGigetError(err: unknown): string {
  const msg = err instanceof Error ? err.message : String(err);
  if (msg.includes('TIMEOUT')) return 'TIMEOUT';
  if (msg.includes('404') || msg.includes('not found')) return 'NOT_FOUND';
  if (msg.includes('401') || msg.includes('403')) return 'AUTH_ERROR';
  if (msg.includes('ENOSPC')) return 'DISK_FULL';
  if (msg.includes('EEXIST')) return 'DIRECTORY_EXISTS';
  if (msg.includes('ENOTFOUND') || msg.includes('fetch')) return 'NETWORK_ERROR';
  return 'UNKNOWN';
}

/**
 * Resolve GitHub auth token from environment or gh CLI.
 */
export async function resolveGitAuth(): Promise<string | undefined> {
  if (process.env.GITHUB_TOKEN) return process.env.GITHUB_TOKEN;
  try {
    const { stdout } = await execAsync('gh auth token');
    return stdout.trim() || undefined;
  } catch {
    return undefined;
  }
}
```

