**File: apps/server/src/routes/templates.ts (new)**

```typescript
import { Router } from 'express';
import * as fs from 'fs/promises';
import * as path from 'path';
import { DEFAULT_TEMPLATES, TemplateCatalogSchema, type TemplateEntry } from '@dorkos/shared/template-catalog';

export function createTemplateRouter(dorkHome: string): Router {
  const router = Router();
  const catalogPath = path.join(dorkHome, 'agent-templates.json');

  async function loadUserTemplates(): Promise<TemplateEntry[]> {
    try {
      const raw = await fs.readFile(catalogPath, 'utf-8');
      const parsed = TemplateCatalogSchema.safeParse(JSON.parse(raw));
      return parsed.success ? parsed.data.templates : [];
    } catch {
      return []; // File doesn't exist yet
    }
  }

  async function saveUserTemplates(templates: TemplateEntry[]): Promise<void> {
    const catalog = { version: 1 as const, templates };
    await fs.writeFile(catalogPath, JSON.stringify(catalog, null, 2));
  }

  // GET /api/templates — returns merged catalog (builtin + user)
  router.get('/', async (_req, res) => {
    const userTemplates = await loadUserTemplates();
    const merged = [...DEFAULT_TEMPLATES, ...userTemplates];
    res.json({ templates: merged });
  });

  // POST /api/templates — adds user template entry
  router.post('/', async (req, res) => {
    const { id, name, description, source, category } = req.body;
    if (!id || !name || !source) {
      return res.status(400).json({ error: 'id, name, and source are required' });
    }
    const entry: TemplateEntry = {
      id,
      name,
      description: description || '',
      source,
      category: category || 'custom',
      builtin: false,
    };
    const userTemplates = await loadUserTemplates();
    if (userTemplates.some(t => t.id === id) || DEFAULT_TEMPLATES.some(t => t.id === id)) {
      return res.status(409).json({ error: 'Template ID already exists' });
    }
    userTemplates.push(entry);
    await saveUserTemplates(userTemplates);
    res.status(201).json(entry);
  });

  // DELETE /api/templates/:id — removes user template (builtin=false only)
  router.delete('/:id', async (req, res) => {
    const { id } = req.params;
    if (DEFAULT_TEMPLATES.some(t => t.id === id)) {
      return res.status(403).json({ error: 'Cannot delete built-in templates' });
    }
    const userTemplates = await loadUserTemplates();
    const filtered = userTemplates.filter(t => t.id !== id);
    if (filtered.length === userTemplates.length) {
      return res.status(404).json({ error: 'Template not found' });
    }
    await saveUserTemplates(filtered);
    res.status(204).send();
  });

  return router;
}
```

