import { useQuery } from '@tanstack/react-query';
import { useTransport } from '@/layers/shared/lib/transport';
import type { TemplateEntry } from '@dorkos/shared/template-catalog';

interface TemplateCatalogResponse {
  templates: TemplateEntry[];
}

export function useTemplateCatalog() {
  const transport = useTransport();

  return useQuery({
    queryKey: ['templates'],
    queryFn: async (): Promise<TemplateEntry[]> => {
      // Use transport or direct fetch depending on transport type
      const response = await fetch('/api/templates');
      if (!response.ok) throw new Error('Failed to fetch templates');
      const data: TemplateCatalogResponse = await response.json();
      return data.templates;
    },
    staleTime: 5 * 60 * 1000, // 5 minutes — catalog rarely changes
    gcTime: 30 * 60 * 1000, // 30 minutes
  });
}
```

