let audioCtx: AudioContext | null = null;

function getAudioContext(): AudioContext {
  if (!audioCtx) {
    audioCtx = new AudioContext();
  }
  return audioCtx;
}

function getSoundEnabled(): boolean {
  // Check user's notification sound preference from settings/config
  // This should integrate with existing settings system
  // For now, default to true unless explicitly disabled
  return true; // TODO: Wire to actual setting
}

/**
 * Play a soft click when a slider moves to a new discrete stop.
 * 4ms sine wave at 800Hz, gain 0.05. Very subtle.
 */
export function playSliderTick(): void {
  if (!getSoundEnabled()) return;
  const ctx = getAudioContext();
  const osc = ctx.createOscillator();
  const gain = ctx.createGain();
  osc.type = 'sine';
  osc.frequency.value = 800;
  gain.gain.value = 0.05;
  osc.connect(gain).connect(ctx.destination);
  osc.start();
  osc.stop(ctx.currentTime + 0.004);
}

/**
 * Play a short ascending 3-note chime on agent creation.
 * C5 (523Hz), E5 (659Hz), G5 (784Hz) — major chord.
 * 100ms total, gain 0.08.
 */
export function playCelebration(): void {
  if (!getSoundEnabled()) return;
  const ctx = getAudioContext();
  const notes = [523, 659, 784]; // C5, E5, G5
  notes.forEach((freq, i) => {
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.type = 'sine';
    osc.frequency.value = freq;
    gain.gain.value = 0.08;
    osc.connect(gain).connect(ctx.destination);
    osc.start(ctx.currentTime + i * 0.033);
    osc.stop(ctx.currentTime + i * 0.033 + 0.05);
  });
}
```

